```python
from aws_cdk import (
    aws_s3 as s3,
    aws_kms as kms,
    core
)

class S3EncryptionStack(core.Stack):

    def __init__(self, scope: core.Construct, id: str, **kwargs) -> None:
        super().__init__(scope, id, **kwargs)

        # 1. Create a KMS Key (if one doesn't already exist)
        #    It's best practice to use an existing KMS key if possible.
        #    If you need to create a new one, uncomment the following lines.
