        #     self, "EncryptionKey",
        #     description="Key for S3 bucket encryption",
        #     removal_policy=core.RemovalPolicy.DESTROY  # Careful with this!
        # )

        # 2. Create the S3 Bucket
        bucket = s3.Bucket(
            self, "SecureS3Bucket",
            removal_policy=core.RemovalPolicy.DESTROY, # Careful with this!
            encryption = s3.BucketEncryptionConfiguration(
                server_side_encryption_algorithm=s3.SseServerSideEncryptionConfiguration(
                    server_side_encryption_by_default=s3.SseServerSideEncryptionConfiguration.SseManaged(
                        sse_type=s3.SseType.KMS
                    )
                )
            )
        )

        # 3. Grant the bucket policy to access the KMS key
        #    This is crucial for the bucket to be able to encrypt data.
        #    This example grants the bucket policy to use the KMS key.
        #    Adjust the ARN to match your KMS key's ARN.
        bucket.add_policy(
            s3.BucketPolicy(
                self, "BucketPolicy",
                bucket=bucket,
                policy_document={
                    "Statement": [
                        {
                            "Effect": "Allow",
                            "Principal": {
                                "AWS": "arn:aws:iam::YOUR_ACCOUNT_ID:role/S3BucketAccessRole"  # Replace with your role ARN
                            },
                            "Action": "kms:Encrypt",
                            "Resource": f"arn:aws:kms:{core.AwsPartition}.{core.AwsRegion.get_region()}:key/YOUR_KMS_KEY_ID" # Replace with your KMS key ARN
                        },
                        {
                            "Effect": "Allow",
                            "Principal": {
                                "AWS": "arn:aws:iam::YOUR_ACCOUNT_ID:role/S3BucketAccessRole"  # Replace with your role ARN
                            },
                            "Action": "kms:Decrypt",
                            "Resource": f"arn:aws:kms:{core.AwsPartition}.{core.AwsRegion.get_region()}:key/YOUR_KMS_KEY_ID" # Replace with your KMS key ARN
                        }
                    ]
                }
            )
        )

        # Output the bucket name
        core.CfnOutput(self, "BucketName", value=bucket.bucket_name)



app = core.App()
